import fs from 'fs/promises';
import path from 'path';
import type {
  GeneratedDocs,
  LumikoConfig,
  ContextBundle,
  ContextManifest,
  DependencyGraph,
} from '../types/index.js';

// Lumiko version is baked into the manifest so agents can tell when a bundle
// was generated by an older version of the generator.
const LUMIKO_VERSION = '1.0.0';

export interface WriteOptions {
  /** Pre-built dep graph. Written alongside the .context/ bundle when present. */
  graph?: DependencyGraph | null;
}

export async function writeOutput(
  docs: GeneratedDocs,
  projectPath: string,
  config: LumikoConfig,
  options: WriteOptions = {},
): Promise<void> {
  const writes: Promise<void>[] = [];

  // ── Markdown docs → config.output.directory (default: docs/) ──────────
  if (
    (config.docs.readme && docs.readme) ||
    (config.docs.architecture && docs.architecture) ||
    (config.docs.api && docs.api)
  ) {
    const outputDir = path.join(projectPath, config.output.directory);
    await fs.mkdir(outputDir, { recursive: true });

    if (config.docs.readme && docs.readme) {
      writes.push(fs.writeFile(path.join(outputDir, 'README.md'), docs.readme + '\n'));
    }
    if (config.docs.architecture && docs.architecture) {
      writes.push(fs.writeFile(path.join(outputDir, 'architecture.md'), docs.architecture + '\n'));
    }
    if (config.docs.api && docs.api) {
      writes.push(fs.writeFile(path.join(outputDir, 'api.md'), docs.api + '\n'));
    }
  }

  // ── .context/ bundle → config.output.contextDirectory (default: .context/) ──
  if (config.output.formats.includes('context') && docs.context && docs.context.entries.length > 0) {
    await writeContextBundle(docs.context, projectPath, config, options.graph ?? null);
  } else if (config.output.formats.includes('context') && options.graph) {
    // Bundle failed or was skipped, but we still want the graph on disk.
    const contextDir = path.join(projectPath, config.output.contextDirectory);
    await fs.mkdir(contextDir, { recursive: true });
    await fs.writeFile(
      path.join(contextDir, 'graph.json'),
      JSON.stringify(options.graph, null, 2) + '\n',
    );
  }

  await Promise.all(writes);
}

