  return Array.from(byPkg.values()).sort((a, b) => a.package.localeCompare(b.package));
}

function sortAlpha<T>(obj: Record<string, T>): Record<string, T> {
  const out: Record<string, T> = {};
  for (const k of Object.keys(obj).sort()) {
    out[k] = obj[k];
  }
  return out;
}

