  ];

  for (const [label, cmd] of standard) {
    if (cmd) {
      lines.push(`- **${label}:** \`${cmd}\``);
    }
  }

  if (commands.custom && Object.keys(commands.custom).length > 0) {
    lines.push('', '### Custom scripts', '');
    for (const [name, cmd] of Object.entries(commands.custom)) {
