    lines.push('');
    for (const entry of graph.stats.mostImported.slice(0, 5)) {
      lines.push(`- \`${entry.path}\` — imported by ${entry.importers} file${entry.importers === 1 ? '' : 's'}`);
    }
    lines.push('');
  }

