  path: string;
  /** Imported symbols — empty for side-effect, ['*'] for namespace. */
  symbols: string[];
  style: ImportStyle;
}

/** One external edge (file → package). */
export interface GraphExternalImport {
  /** Package name (e.g. "commander", "@anthropic-ai/sdk"). */
  package: string;
