/**
 * Schema for manifest.json — bundle index + metadata (generated locally, not by Claude).
 */
export interface ContextManifest {
  lumiko: {
    version: string;
    generatedAt: string;
    model: string;
  };
  project: {
    name: string;
    summary: string;
  };
